{"patient_id": "129", "personal_information": {"name": "", "gender": "Female", "dob": "1998-02-22", "age": 28}, "vitals": {}, "lab_results": [], "radiology_reports": [{"cpt_id": "1000000000073202", "cpt_name": "C.T. Sinus without Contrast", "technique": "Multiple axial sections were taken through the region of paranasal sinuses without IV contrast injection.", "result": "Complete opacification of bilateral maxillary sinuses with extension of soft tissue densities into the nasal cavities and ethmoidal air cells through widened sinus ostia. There is complete opacification of the sphenoid sinus. The frontal sinuses are also completely opaque. 
